#include <bits/stdc++.h>
using namespace std;
int n,m,t[10004],c[10004],p[10004],dp[10004][1003];
int main(){
	int tmp[4];
	scanf("%d:%d %d:%d %d",&tmp[0],&tmp[1],&tmp[2],&tmp[3],&n);
	m=tmp[3]-tmp[1]+(tmp[2]-tmp[0])*60;
	for(int i=1;i<=n;i++)
		scanf("%d%d%d",&t[i],&c[i],&p[i]);
	for(int i=1;i<=n;i++)
		for(int j=1;j<=m;j++)
			if(!p[i])
				if(j>=t[i])
					dp[i][j]=max(dp[i-1][j],dp[i][j-t[i]]+c[i]);
				else
					dp[i][j]=dp[i-1][j];
			else
				for(int k=0;k<=p[i] && t[i]*k<=j;k++)
					if(dp[i-1][j-t[i]*k]+c[i]*k>dp[i][j])
						dp[i][j]=dp[i-1][j-t[i]*k]+c[i]*k;
	printf("%d",dp[n][m]);
	return 0;
}
